"""Generate all MiniLab PNG figures."""

from __future__ import annotations

import sys
from pathlib import Path

PROJECT_ROOT = Path(__file__).resolve().parents[1]
if str(PROJECT_ROOT) not in sys.path:
    sys.path.insert(0, str(PROJECT_ROOT))

from experiments.plot_results import generate_all_plots
from experiments.run_experiments import RESULTS_DIR


def plot_all_results(results_dir: Path | str = RESULTS_DIR) -> list[Path]:
    """Save all PNG figures generated by the core experiment suite."""

    return generate_all_plots(results_dir)


def main() -> None:
    for path in plot_all_results():
        print(path)


if __name__ == "__main__":
    main()
